    const path = "/api/" + params.$0;
    return new Response(
      JSON.stringify({ error: "not_found", path }),
      {
        status: 404,
        headers: { "Content-Type": "application/json" },
      },
    );
  }),

  // ── except handlers (placed after all routes so they catch errors
  //     from any preceding route) ──

  // This except catches errors from non-API routes (HTML routes)
  except((error: unknown, { response, path }) => {
    // Only handle non-API errors here
    if (path.startsWith("/api/")) {
      return; // let the next except handler deal with it
    }
    console.error("HTML error caught:", error);
    response.status = 500;
    return <ServerError />;
  }),

  // This except catches errors from API routes
  except((error: unknown, { path }) => {
    // Only handle API errors here
    if (!path.startsWith("/api/")) {
      return; // let the previous except handler deal with it
    }
    console.error("API error caught:", error);
    return new Response(
      JSON.stringify({ error: "internal_server_error" }),
      {
        status: 500,
        headers: { "Content-Type": "application/json" },
      },
    );
  }),
]);
